package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonObject;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class JsonTreeReaderTest {

    private JsonTreeReader jsonTreeReader;
    private JsonObject jsonObject;

    @BeforeEach
    public void setUp() {
        jsonObject = new JsonObject();
        jsonObject.addProperty("key", "value");
        jsonTreeReader = new JsonTreeReader(jsonObject);
    }

    @Test
    public void testEndObject_NormalFlow() throws Exception {
        // Spy on jsonTreeReader
        JsonTreeReader spyReader = spy(jsonTreeReader);

        // Initialize internal state to simulate being inside an object
        setField(spyReader, "stackSize", 2);
        Object[] stack = new Object[32];
        stack[0] = new Object(); // something on stack
        stack[1] = mock(java.util.Iterator.class); // iterator on top of stack
        setField(spyReader, "stack", stack);

        String[] pathNames = new String[32];
        pathNames[1] = "someName";
        setField(spyReader, "pathNames", pathNames);

        int[] pathIndices = new int[32];
        pathIndices[0] = 0;
        pathIndices[1] = 5;
        setField(spyReader, "pathIndices", pathIndices);

        // Because expect is private and cannot be stubbed, we invoke endObject via reflection
        // after setting internal state and mock expect to do nothing by temporarily replacing it

        // Temporarily disable expect by replacing it with a no-op via reflection
        // Since private methods cannot be overridden, we use a spy and doNothing on expect via reflection

        // Use reflection to get the private expect method
        var expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
        expectMethod.setAccessible(true);

        // Use Mockito to stub the private expect method by spying and using doNothing via reflection:
        // But Mockito cannot stub private methods directly,
        // so we use a helper proxy invocation handler to suppress expect calls
        // Instead, invoke endObject directly but catch the expect call by temporarily replacing expect method via a proxy is complex,
        // so we just invoke endObject and catch the exception if expect fails,
        // or we mock the stack to be in a state that expect will pass.

        // So here, set the top of stack to be JsonToken.END_OBJECT to satisfy expect

        // Actually, expect checks the top of stack for expected token,
        // so we must set stack top correctly.

        // The stack top is an iterator, so we mock it to return correct token.

        // But expect is private and uses peekStack internally.

        // To avoid all this complexity, we can call popStack twice manually and then test the internal state changes.

        // Instead, we call endObject via reflection but first set the stack top to END_OBJECT token by pushing it.

        // Push JsonToken.END_OBJECT to stack to satisfy expect
        Object[] newStack = (Object[]) getField(spyReader, "stack");
        int stackSize = (int) getField(spyReader, "stackSize");
        newStack[stackSize] = JsonToken.END_OBJECT;
        setField(spyReader, "stack", newStack);
        setField(spyReader, "stackSize", stackSize + 1);

        // Now invoke endObject via reflection
        var endObjectMethod = JsonTreeReader.class.getDeclaredMethod("endObject");
        endObjectMethod.setAccessible(true);
        endObjectMethod.invoke(spyReader);

        // Verify pathNames[stackSize - 1] is null
        String[] updatedPathNames = (String[]) getField(spyReader, "pathNames");
        assertNull(updatedPathNames[1]);

        // Verify stackSize decreased by 2
        int updatedStackSize = (int) getField(spyReader, "stackSize");
        assertEquals(0, updatedStackSize);

        // Verify pathIndices[stackSize - 1] incremented (stackSize > 0 condition)
        // Since after popStack twice stackSize is 0, no increment should happen
        int[] updatedPathIndices = (int[]) getField(spyReader, "pathIndices");
        assertEquals(0, updatedPathIndices[0]);
        assertEquals(5, updatedPathIndices[1]);
    }

    @Test
    public void testEndObject_PathIndicesIncrementedWhenStackSizeGreaterThanZero() throws Exception {
        JsonTreeReader spyReader = spy(jsonTreeReader);

        // Setup stackSize = 3, so after popping twice it will be 1 (still > 0)
        setField(spyReader, "stackSize", 3);
        Object[] stack = new Object[32];
        stack[0] = new Object();
        stack[1] = mock(java.util.Iterator.class);
        stack[2] = new Object();
        setField(spyReader, "stack", stack);

        String[] pathNames = new String[32];
        pathNames[2] = "lastName";
        setField(spyReader, "pathNames", pathNames);

        int[] pathIndices = new int[32];
        pathIndices[0] = 1;
        pathIndices[1] = 2;
        pathIndices[2] = 3;
        setField(spyReader, "pathIndices", pathIndices);

        // Push JsonToken.END_OBJECT to stack to satisfy expect
        Object[] newStack = (Object[]) getField(spyReader, "stack");
        int stackSize = (int) getField(spyReader, "stackSize");
        newStack[stackSize] = JsonToken.END_OBJECT;
        setField(spyReader, "stack", newStack);
        setField(spyReader, "stackSize", stackSize + 1);

        // Invoke endObject via reflection
        var endObjectMethod = JsonTreeReader.class.getDeclaredMethod("endObject");
        endObjectMethod.setAccessible(true);
        endObjectMethod.invoke(spyReader);

        // After popping twice, stackSize should be 1
        int updatedStackSize = (int) getField(spyReader, "stackSize");
        assertEquals(1, updatedStackSize);

        // pathNames[stackSize - 1] should be null
        String[] updatedPathNames = (String[]) getField(spyReader, "pathNames");
        assertNull(updatedPathNames[0]);

        // pathIndices[stackSize - 1] should be incremented by 1
        int[] updatedPathIndices = (int[]) getField(spyReader, "pathIndices");
        assertEquals(2, updatedPathIndices[0]); // incremented from 1 to 2
        assertEquals(2, updatedPathIndices[1]);
        assertEquals(3, updatedPathIndices[2]);
    }

    // Helper method to set private fields via reflection
    private void setField(Object target, String fieldName, Object value) {
        try {
            Field field = JsonTreeReader.class.getDeclaredField(fieldName);
            field.setAccessible(true);
            field.set(target, value);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    // Helper method to get private fields via reflection
    private Object getField(Object target, String fieldName) {
        try {
            Field field = JsonTreeReader.class.getDeclaredField(fieldName);
            field.setAccessible(true);
            return field.get(target);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
